13→// Preferences is the typed representation of the JSONB data column.
14→type Preferences struct {
15→	HomeLatitude  *float64 `json:"homeLatitude,omitempty"`
16→	HomeLongitude *float64 `json:"homeLongitude,omitempty"`
17→	HomeState     *string  `json:"homeState,omitempty"`
18→}
19→
20→// Service manages user preferences in the ugc schema.
21→type Service struct {
22→	pool *pgxpool.Pool
23→}
24→
25→// NewService returns a new preference service.
26→func NewService(pool *pgxpool.Pool) *Service {
27→	return &Service{pool: pool}
28→}
29→
30→// TeamIDForUser looks up the team_id for a given user_id.
31→func (s *Service) TeamIDForUser(ctx context.Context, userID string) (string, error) {
32→	var teamID string
33→	err := s.pool.QueryRow(ctx,
34→		`SELECT team_id FROM subscription.team_member WHERE user_id = $1`, userID,
35→	).Scan(&teamID)
36→	if err != nil {
37→		return "", fmt.Errorf("preference: team for user %s: %w", userID, err)
38→	}
39→	return teamID, nil
40→}
41→
42→// Get retrieves preferences for the given team. Returns zero-value Preferences
43→// if no row exists.
44→func (s *Service) Get(ctx context.Context, teamID string) (*Preferences, error) {
45→	var data []byte
46→	err := s.pool.QueryRow(ctx,
47→		`SELECT data FROM ugc.preference WHERE team_id = $1`, teamID,
48→	).Scan(&data)
49→	if err != nil {
50→		if errors.Is(err, pgx.ErrNoRows) {
51→			return &Preferences{}, nil
52→		}
53→		return nil, fmt.Errorf("preference: get for team %s: %w", teamID, err)
54→	}
55→	var prefs Preferences
56→	if err := json.Unmarshal(data, &prefs); err != nil {
57→		return nil, fmt.Errorf("preference: unmarshal for team %s: %w", teamID, err)
58→	}
59→	return &prefs, nil
60→}
61→
62→// Update upserts the preferences for the given team.
63→func (s *Service) Update(ctx context.Context, teamID string, prefs *Preferences) (*Preferences, error) {
64→	data, err := json.Marshal(prefs)
65→	if err != nil {
66→		return nil, fmt.Errorf("preference: marshal: %w", err)
67→	}
68→
69→	var result []byte
70→	err = s.pool.QueryRow(ctx, `
71→		INSERT INTO ugc.preference (team_id, data)
72→		VALUES ($1, $2)
73→		ON CONFLICT (team_id) DO UPDATE
74→			SET data = $2, updated = CURRENT_TIMESTAMP
75→		RETURNING data`,
76→		teamID, data,
77→	).Scan(&result)
78→	if err != nil {
79→		return nil, fmt.Errorf("preference: update for team %s: %w", teamID, err)
80→	}
81→
82→	var updated Preferences
83→	if err := json.Unmarshal(result, &updated); err != nil {
84→		return nil, fmt.Errorf("preference: unmarshal result for team %s: %w", teamID, err)
85→	}
86→	return &updated, nil
87→}
